241	/// Discover the sentry's enclave IP by reading /etc/resolv.conf from the pentacle via fiat.
242	/// The pentacle uses the sentry as its DNS server, so resolv.conf nameserver = sentry enclave IP.
243	/// (Sentry's own resolv.conf points to upstream DNS like 8.8.8.8 — wrong for enclave ops.)
244	fn rbtdrc_discover_sentry_ip(ctx: &mut rbtdri_Context) -> Result<String, String> {
245	    let output = rbtdrc_fiat(ctx, &["cat", "/etc/resolv.conf"])?;
246	    for line in output.lines() {
247	        let trimmed = line.trim();
248	        if let Some(rest) = trimmed.strip_prefix("nameserver") {
249	            let ip = rest.trim();
250	            if !ip.is_empty() && rbtdrc_looks_like_ip(ip) {
251	                return Ok(ip.to_string());
252	            }
253	        }
254	    }
255	    Err(format!(
256	        "no nameserver found in pentacle /etc/resolv.conf:\n{}",
257	        output
258	    ))
259	}
