261	/// Resolve a hostname via writ (running dig +short on the sentry).
262	/// Returns the first line that looks like an IP address (filters BUK log headers).
263	fn rbtdrc_resolve_via_writ(ctx: &mut rbtdri_Context, hostname: &str) -> Result<String, String> {
264	    let output = rbtdrc_writ(ctx, &["dig", "+short", hostname])?;
265	    let ip = output
266	        .lines()
267	        .find(|line| {
268	            let t = line.trim();
269	            !t.is_empty() && rbtdrc_looks_like_ip(t)
270	        })
271	        .map(|line| line.trim().to_string())
272	        .ok_or_else(|| format!("dig +short {} returned no IP:\n{}", hostname, output))?;
273	    Ok(ip)
274	}
