276	/// Quick check: does this string look like an IPv4 address (digits and dots only)?
277	/// Not a full validator — just enough to reject BUK log headers and DNS comments.
278	fn rbtdrc_looks_like_ip(s: &str) -> bool {
279	    !s.is_empty() && s.chars().all(|c| c.is_ascii_digit() || c == '.')
280	}
281	
282	/// Extract iptables rule lines from writ output, filtering BUK log headers.
283	/// Rules start with -P (policy), -N (new chain), or -A (append).
284	fn rbtdrc_extract_iptables_rules(output: &str) -> String {
285	    output
286	        .lines()
287	        .filter(|l| {
288	            let t = l.trim();
289	            t.starts_with("-P ") || t.starts_with("-N ") || t.starts_with("-A ")
290	        })
291	        .collect::<Vec<_>>()
292	        .join("\n")
293	}
294	
295	/// Filter writ output to remove BUK log headers (lines starting with known prefixes).
296	/// Retains only the actual command output.
297	fn rbtdrc_filter_writ_output(output: &str) -> String {
298	    output
299	        .lines()
300	        .filter(|l| {
301	            let t = l.trim();
302	            !t.starts_with("log files:")
303	                && !t.starts_with("transcript:")
304	                && !t.starts_with("output dir:")
305	                && !t.starts_with("\u{1b}[90m") // ANSI escape for BUK colored prefix
306	        })
307	        .collect::<Vec<_>>()
308	        .join("\n")
309	}
