316	            Ok(ip) => ip,
317	            Err(e) => return rbtdre_Verdict::Fail(format!("sentry IP discovery: {}", e)),
318	        };
319	        let _ = std::fs::write(dir.join("sentry-ip.txt"), &sentry_ip);
